// Transform Supabase task to n8n Data Table format
// FIXED VERSION: Handles variable replacement + stage routing for ALL tasks

const task = $input.item.json;
const templates = $('Get all row(s) from prompt-template').all();

// --- Helper: Safe parse JSONB fields ---
const parseSafe = (val, fallback) => {
    if (val === null || val === undefined) return fallback;
    if (typeof val === 'object') return val;
    try {
        let parsed = JSON.parse(val);
        if (typeof parsed === 'string') parsed = JSON.parse(parsed);
        return parsed;
    } catch (e) { return fallback; }
};

// --- 1. PREPARE DATA SOURCES ---
let taskExtra = parseSafe(task.extra, {});
const inputData = parseSafe(task.input_data, {});  // parseSafe: handles JSONB string or object

const enrichmentData = {
    ...task,
    ...taskExtra,
    ...inputData
};

// --- 2. IDENTIFY TEMPLATE & CONFIG ---
const templateId = task.prompt_template_id;
const templateItem = templates.find(t => t.json.id === templateId || t.json.prompt_id === templateId);
const cachedTemplate = templateItem ? templateItem.json : null;

let delimiters = { start: '%%', end: '%%' };
if (cachedTemplate && cachedTemplate.prompt_input_schema) {
    try {
        const schema = parseSafe(cachedTemplate.prompt_input_schema, {});
        if (schema.delimiters) delimiters = schema.delimiters;
    } catch (e) { /* use defaults */ }
}

// --- 3. PROCESS PROMPT (VARIABLE REPLACEMENT) ---
let rawPrompt = task.prompt;
if ((!rawPrompt || rawPrompt.trim() === '') && cachedTemplate) {
    rawPrompt = cachedTemplate.template || '';
}
if (!rawPrompt) rawPrompt = '';

const escapeRegex = (s) => s.replace(/[.*+?^${}()|[\\]\\]/g, '\\$&');
const regex = new RegExp(escapeRegex(delimiters.start) + '\\s*([\\w_]+)\\s*' + escapeRegex(delimiters.end), 'g');

const finalPrompt = rawPrompt.replace(regex, (match, key) => {
    if (enrichmentData.hasOwnProperty(key)) {
        const value = enrichmentData[key];
        if (typeof value === 'object' && value !== null) {
            return JSON.stringify(value, null, 2);
        }
        return String(value);
    }
    return match;
});

// --- 4. PROCESS AI SETTINGS ---
let aiSettingsRaw = task.ai_settings;
if (!aiSettingsRaw && cachedTemplate) {
    aiSettingsRaw = cachedTemplate.default_ai_settings || cachedTemplate.ai_settings;
}

let finalAiSettings = {};
const fallbackGenConfig = {
    temperature: 1.0,
    topP: 0.95,
    topK: 40,
    maxOutputTokens: 8192,
    thinkingConfig: { includeThoughts: false, thinkingBudget: -1 }
};

try {
    const parsed = parseSafe(aiSettingsRaw, {});
    finalAiSettings = {
        model_id: parsed.model_id || 'gemini-1.5-flash',
        generate_content_api: parsed.generate_content_api || 'generateContent',
        generationConfig: {
            ...fallbackGenConfig,
            ...(parsed.generationConfig || {})
        },
        safetySettings: parsed.safetySettings || [],
        systemInstruction: parsed.systemInstruction || undefined,
        tools: parsed.tools || undefined
    };
} catch (e) {
    console.error('Failed to parse AI settings, using safe defaults', e);
    finalAiSettings = { 
        model_id: 'gemini-1.5-flash', 
        generationConfig: fallbackGenConfig 
    };
}

// --- 5. PROCESS STAGE CONFIG & NEXT STAGE CONFIGS ---
let currentStageConfig = null;
let nextStageConfigs = [];

if (cachedTemplate) {
    // 5a. Current stage config from template's stage_config
    if (cachedTemplate.stage_config) {
        currentStageConfig = parseSafe(cachedTemplate.stage_config, null);
        // Inject template_id into current config for reference
        if (currentStageConfig) {
            currentStageConfig.template_id = cachedTemplate.id;
        }
    }

    // 5b. Build next_stage_configs from next_stage_template_ids
    let nextIdsStr = (cachedTemplate && cachedTemplate.next_stage_template_ids) || task.next_stage_template_ids || [];
    let nextIds = parseSafe(nextIdsStr, []);
    if (!Array.isArray(nextIds)) nextIds = nextIds ? [nextIds] : [];

    nextStageConfigs = nextIds.map(nextId => {
        const nextTpl = templates.find(t => t.json.id === nextId || t.json.prompt_id === nextId);
        if (!nextTpl) return null;
        const nextSc = parseSafe(nextTpl.json.stage_config, {});
        return {
            template_id: nextId,
            cardinality: nextSc.cardinality || 'one_to_one',
            split_path: nextSc.split_path || null,
            split_mode: nextSc.split_mode || 'per_item',
            merge_path: nextSc.merge_path || null,
            output_mapping: nextSc.output_mapping || 'result',
            batch_grouping: nextSc.batch_grouping || null,
            requires_approval: nextSc.requires_approval || false
        };
    }).filter(Boolean);
}

// Build stageConfig object for merging into extra
const stageConfigObj = {};
if (currentStageConfig) stageConfigObj.current_stage_config = currentStageConfig;
if (nextStageConfigs.length > 0) stageConfigObj.next_stage_configs = nextStageConfigs;

// Merge extra data for output
const mergedExtra = { ...taskExtra, ...(inputData.extra || {}), ...stageConfigObj };

// --- 6. FINAL OUTPUT ---
return {
  json: {
    // Preserve original task data
    ...task,

    // --- TRANSFORMED FIELDS ---
    task_id: '',
    extra: JSON.stringify(mergedExtra),
    data: JSON.stringify(inputData),
    prompt: finalPrompt,
    ai_settings: JSON.stringify(finalAiSettings),
    status: 'plan',
    result: '',

    // --- MAPPED METADATA ---
    supabase_task_id: task.id,
    task_type: task.task_type,
    agent_id: task.agent_id || 'agent_1',
    batch_id: task.batch_id || '',
    launch_id: task.launch_id || '',
    batch_priority: task.batch_priority || '',
    user_id: task.user_id || '',
    test_mode: task.test_mode || false,
    sequence: task.sequence || 1,
    requires_approval: task.requires_approval || false,
    prompt_template_id: task.prompt_template_id || '',
    next_stage_template_id: task.next_stage_template_id || '',

    // Hierarchy & Metadata
    parent_task_id: task.parent_task_id || '',
    split_group_id: task.split_group_id || '',
    stage_key: task.stage_key || '',
    root_task_id: task.root_task_id || '',
    hierarchy_path: task.hierarchy_path,
    created_at: task.created_at || '',
    started_at: task.started_at || '',
    completed_at: task.completed_at || '',
    batch_status: task.batch_status || '',
    batch_name: task.batch_name || ''
  }
};
